CREATE OR REPLACE VIEW sclawlon_bal (loan_contract_no, bf_prin, bf_intarr, bf_period_payment, bf_last_period, bf_last_calint, af_prin, af_intarr, af_period_payment, af_last_period, af_last_calint) AS SELECT sc_lon_m_trans_loan_coll_head.loan_contract_no
, principal_balance as BF_PRIN
, interest_arrear + int_transfer_amount as BF_INTARR
, period_payment as BF_PERIOD_PAYMENT
, ( select last_period 
	FROM sc_lon_m_loan_card 
	where loan_contract_no = sc_lon_m_trans_loan_coll_head.loan_contract_no ) as BF_LAST_PERIOD

, last_calcint_date as BF_LAST_CALINT

, (  select sum(principal_balance ) 
		from sc_lon_m_loan_card
      ,sc_lon_m_trans_loan_coll_det
		where sc_lon_m_trans_loan_coll_det.new_contract_no = sc_lon_m_loan_card.loan_contract_no 
		and  sc_lon_m_trans_loan_coll_det.transfer_doc_no = sc_lon_m_trans_loan_coll_head.transfer_doc_no 
  ) as AF_PRIN 

, (  select sum(interest_arrear ) 
		from sc_lon_m_loan_card
      ,sc_lon_m_trans_loan_coll_det
		where sc_lon_m_trans_loan_coll_det.new_contract_no = sc_lon_m_loan_card.loan_contract_no 
		and  sc_lon_m_trans_loan_coll_det.transfer_doc_no = sc_lon_m_trans_loan_coll_head.transfer_doc_no 
  ) as AF_INTARR 


, (  select sum(period_payment_amount ) 
		from sc_lon_m_contract
      ,sc_lon_m_trans_loan_coll_det
		where sc_lon_m_trans_loan_coll_det.new_contract_no = sc_lon_m_contract.loan_contract_no 
		and  sc_lon_m_trans_loan_coll_det.transfer_doc_no = sc_lon_m_trans_loan_coll_head.transfer_doc_no 
  ) as AF_PERIOD_PAYMENT 


, (  select  max(last_period ) 
		from sc_lon_m_loan_card
      ,sc_lon_m_trans_loan_coll_det
		where sc_lon_m_trans_loan_coll_det.new_contract_no = sc_lon_m_loan_card.loan_contract_no 
		and  sc_lon_m_trans_loan_coll_det.transfer_doc_no = sc_lon_m_trans_loan_coll_head.transfer_doc_no 
  ) as AF_LAST_PERIOD 

, (  select  max(last_calcint_date ) 
		from sc_lon_m_loan_card
      ,sc_lon_m_trans_loan_coll_det
		where sc_lon_m_trans_loan_coll_det.new_contract_no = sc_lon_m_loan_card.loan_contract_no 
		and  sc_lon_m_trans_loan_coll_det.transfer_doc_no = sc_lon_m_trans_loan_coll_head.transfer_doc_no 
  ) as AF_LAST_CALINT 


    FROM sc_lon_m_trans_loan_coll_head  
   WHERE sc_lon_m_trans_loan_coll_head.transfer_status = '0';

